#include <omp.h>
#include <math.h>

#include "./../main.h"

void kernel_gpu_cuda_wrapper(par_str par_cpu,
							 dim_str dim_cpu,
							 box_str* box_cpu,
							 FOUR_VECTOR* rv_cpu,
							 fp* qv_cpu,
							 FOUR_VECTOR* fv_cpu)
{
	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	time0 = get_time();

	int number_boxes = (int)dim_cpu.number_boxes;

	time1 = get_time();

	time2 = time1;

	time3 = time2;

#pragma omp parallel
	{
		int tx = omp_get_thread_num();
		int nthreads = omp_get_num_threads();

		fp a2 = 2.0 * par_cpu.alpha * par_cpu.alpha;

#pragma omp for schedule(static)
		for (int bx = 0; bx < number_boxes; bx++) {

			int first_i = (int)box_cpu[bx].offset;
			FOUR_VECTOR* rA = &rv_cpu[first_i];
			FOUR_VECTOR* fA = &fv_cpu[first_i];

			FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];

			for (int wtx = tx; wtx < NUMBER_PAR_PER_BOX; wtx += nthreads) {
				rA_shared[wtx] = rA[wtx];
			}

#pragma omp barrier

			for (int k = 0; k < 1 + box_cpu[bx].nn; k++) {

				int pointer;
				if (k == 0) {
					pointer = bx;
				}
				else {
					pointer = box_cpu[bx].nei[k - 1].number;
				}

				int first_j = (int)box_cpu[pointer].offset;
				FOUR_VECTOR* rB = &rv_cpu[first_j];
				fp* qB = &qv_cpu[first_j];

				FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
				double qB_shared[NUMBER_PAR_PER_BOX];

				for (int wtx = tx; wtx < NUMBER_PAR_PER_BOX; wtx += nthreads) {
					rB_shared[wtx] = rB[wtx];
					qB_shared[wtx] = qB[wtx];
				}

#pragma omp barrier

				for (int wtx = tx; wtx < NUMBER_PAR_PER_BOX; wtx += nthreads) {

					for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {

						fp r2 = (fp)rA_shared[wtx].v + (fp)rB_shared[j].v - DOT((fp)rA_shared[wtx], (fp)rB_shared[j]);
						fp u2 = a2 * r2;
						fp vij = exp(-u2);
						fp fs = 2 * vij;

						THREE_VECTOR d;
						d.x = (fp)rA_shared[wtx].x - (fp)rB_shared[j].x;
						fp fxij = fs * d.x;
						d.y = (fp)rA_shared[wtx].y - (fp)rB_shared[j].y;
						fp fyij = fs * d.y;
						d.z = (fp)rA_shared[wtx].z - (fp)rB_shared[j].z;
						fp fzij = fs * d.z;

						fA[wtx].v += (double)((fp)qB_shared[j] * vij);
						fA[wtx].x += (double)((fp)qB_shared[j] * fxij);
						fA[wtx].y += (double)((fp)qB_shared[j] * fyij);
						fA[wtx].z += (double)((fp)qB_shared[j] * fzij);
					}
				}

#pragma omp barrier
			}
		}
	}

	time4 = get_time();

	time5 = time4;

	time6 = time5;

	printf("Time spent in different stages of CPU OpenMP KERNEL:\n");

	printf("%15.12f s, %15.12f % : CPU: SETUP\n", (float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: ALLOC\n", (float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: COPY IN\n", (float)(time3 - time2) / 1000000, (float)(time3 - time2) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: KERNEL\n", (float)(time4 - time3) / 1000000, (float)(time4 - time3) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: COPY OUT\n", (float)(time5 - time4) / 1000000, (float)(time5 - time4) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: FREE\n", (float)(time6 - time5) / 1000000, (float)(time6 - time5) / (float)(time6 - time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", (float)(time6 - time0) / 1000000);

}
